const icp = $input.first().json;

const subreddits = (icp.subreddits || 'SaaS,Entrepreneur,AI_Agents')
  .split(',')
  .map(s => 'r/' + s.trim())
  .join(', ');

const body = {
  model: 'claude-haiku-4-5',
  max_tokens: 2000,
  tools: [{ type: 'web_search_20250305', name: 'web_search', max_uses: 3 }],
  system: `You are a customer-discovery research agent for a lean startup.

ICP context:
${icp.icp_description || ''}

Signal keywords: ${icp.signal_keywords || ''}

Return ONLY a JSON array. No prose. No explanation.`,
  messages: [
    {
      role: 'user',
      content: `Use web_search to find recent (last 7 days) public posts on Hacker News, Reddit (${subreddits}), and Product Hunt where founders or operators are publicly displaying signals matching my ICP. Look for: pain mentions, hiring posts I could solve, complaints about competitors, asks for tools.

Return a JSON array, max 30 items. Each item has: person (handle), signal_type (pain|hiring|complaint|tool_ask), source_url, evidence_quote (verbatim), score (0-10), company, company_url.`
    }
  ]
};

return [{ json: { body } }];

const response = $input.first().json;
const contentBlocks = response.content || [];

let rawText = '';
for (const block of contentBlocks) {
  if (block.type === 'text' && block.text) {
    rawText += block.text;
  }
}

const jsonMatch = rawText.match(/\[[\s\S]*\]/);
if (!jsonMatch) {
  return [{ json: { error: 'No JSON array in response', raw: rawText, leads: [] } }];
}

let leads;
try {
  leads = JSON.parse(jsonMatch[0]);
} catch (e) {
  return [{ json: { error: 'JSON parse failed', message: e.message, raw: jsonMatch[0], leads: [] } }];
}

const qualified = leads.filter(l => (l.score ?? 0) >= 6);

return qualified.map(lead => ({ json: lead }));

const leads = $input.all().map(i => i.json);
const sentRows = $('Read Sent log').all().map(i => i.json);

const contactedUrls    = new Set(sentRows.map(r => r.source_url).filter(Boolean));
const contactedHandles = new Set(sentRows.map(r => r.person).filter(Boolean));

const fresh = leads.filter(lead => {
  if (lead.source_url && contactedUrls.has(lead.source_url)) return false;
  if (lead.person     && contactedHandles.has(lead.person))    return false;
  return true;
});

fresh.sort((a, b) => (b.score ?? 0) - (a.score ?? 0));
const top5 = fresh.slice(0, 5);

return top5.map(lead => ({ json: lead }));

const firecrawl = $input.first().json;
const markdown = (firecrawl.data && firecrawl.data.markdown) ? firecrawl.data.markdown : '';

const body = {
  model: 'claude-haiku-4-5',
  max_tokens: 300,
  system: 'You write concise 2-line company summaries for a lean startup outreach agent. Output plain text. No JSON. No markdown.',
  messages: [
    {
      role: 'user',
      content: `Company markdown extract:

${markdown.slice(0, 4000)}

In exactly two sentences, what does this company do and what is their current state?`
    }
  ]
};

return [{ json: { body, lead: firecrawl } }];

const summary = $input.first().json;
const summaryText = (summary.content && summary.content[0] && summary.content[0].text) ? summary.content[0].text : '';

const lead = $('Dedup · top 5 fresh leads').item.json;

const voiceBuffer = $('Read voice.md from Drive').item.binary.voiceMd;
const voiceMd = voiceBuffer ? Buffer.from(voiceBuffer.data, 'base64').toString('utf-8') : '';

const body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 600,
  system: [
    {
      type: 'text',
      text: 'You write customer-discovery emails for a lean startup founder. Goal of every email: an INTERVIEW ASK, not a pitch. Soft CTA. 80-110 words. Follow the voice.md file exactly.'
    },
    {
      type: 'text',
      text: `voice.md contents:\n\n${voiceMd}`,
      cache_control: { type: 'ephemeral' }
    }
  ],
  messages: [
    {
      role: 'user',
      content: `Draft a customer-discovery email.

Person: ${lead.person || 'unknown'}
Their signal: ${lead.signal_type || ''} - ${lead.evidence_quote || ''}
Source URL: ${lead.source_url || ''}
Company context (2 sentences): ${summaryText}

Return ONLY the email subject and body in this format:
SUBJECT: [subject line]
BODY:
[email body]`
    }
  ]
};

return [{ json: { body, lead } }];

const response = $input.first().json;
const text = (response.content?.[0]?.text || '').trim();

const subjectMatch = text.match(/^SUBJECT:\s*(.+?)\s*\n/);
const bodyMatch    = text.match(/BODY:\s*\n([\s\S]+)$/);

const subject = subjectMatch ? subjectMatch[1].trim() : 're: a quick question';
const body    = bodyMatch ? bodyMatch[1].trim() : text;

const lead = $('Build Draft Body').item.json.lead;

return [{ json: { subject, body, lead } }];

const discoveryCount = $('Discovery · Claude Haiku 4.5 + web_search').all().length;
const qualifiedCount = $('Parse · Extract qualified leads').all().length;
const dedupCount     = $('Dedup · top 5 fresh leads').all().length;
const draftCount     = $('Parse · Subject + Body').all().length;
const signalTypes    = $('Dedup · top 5 fresh leads').all().map(i => i.json.signal_type).join(', ');

const body = {
  model: 'claude-sonnet-4-6',
  max_tokens: 400,
  system: 'You write a brief daily digest email for a founder running a customer-discovery agent. One paragraph. Friendly. Specific numbers.',
  messages: [
    {
      role: 'user',
      content: `Today the agent processed ${discoveryCount} discovery results, scored ${qualifiedCount} as qualified, deduped to ${dedupCount} fresh leads, and drafted ${draftCount} emails sitting in Gmail Drafts.

Top signal types today: ${signalTypes}

Write a short morning digest email to the founder. Subject + body. Friendly tone. Tell them what to do next (approve drafts before 5pm).`
    }
  ]
};

return [{ json: { body } }];

const response = $input.first().json;
const text = (response.content?.[0]?.text || '').trim();

const subjectMatch = text.match(/^SUBJECT:\s*(.+?)\s*\n/i) || text.match(/^Subject:\s*(.+?)\s*\n/);
const bodyMatch    = text.match(/(?:BODY:|Body:)\s*\n([\s\S]+)$/i);

const subject = subjectMatch ? subjectMatch[1].trim() : 'Discovery Pulse — ' + new Date().toISOString().slice(0,10);
const body    = bodyMatch ? bodyMatch[1].trim() : text;

return [{ json: { subject, body } }];
